fn create_client(
    api_key: String,
    base_url: Option<String>,
    timeout_secs: Option<u64>,
    max_retries: Option<u32>,
    model_hint: Option<String>,
) -> Result<DefaultClient, Error> {
    let result =
        liter_llm::bindings::create_client(api_key, base_url, timeout_secs, max_retries, model_hint).map_err(|e| {
            magnus::Error::new(
                unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
                e.to_string(),
            )
        })?;
    Ok(DefaultClient {
        inner: Arc::new(result),
    })
}

fn create_client_from_json(json: String) -> Result<DefaultClient, Error> {
    let result = liter_llm::bindings::create_client_from_json(&json).map_err(|e| {
        magnus::Error::new(
            unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
            e.to_string(),
        )
    })?;
    Ok(DefaultClient {
        inner: Arc::new(result),
    })
}

fn register_custom_provider(config: String) -> Result<(), Error> {
    let config: CustomProviderConfig = {
        let core: liter_llm::CustomProviderConfig = serde_json::from_str(&config)
            .map_err(|e| magnus::Error::new(unsafe { Ruby::get_unchecked() }.exception_type_error(), e.to_string()))?;
        core.into()
    };
    let result = liter_llm::provider::custom::register_custom_provider(config.into()).map_err(|e| {
        magnus::Error::new(
            unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
            e.to_string(),
        )
    })?;
    Ok(result)
}

fn unregister_custom_provider(name: String) -> Result<bool, Error> {
    let result = liter_llm::provider::custom::unregister_custom_provider(&name).map_err(|e| {
        magnus::Error::new(
            unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
            e.to_string(),
        )
    })?;
    Ok(result)
}

